```typescript
import { useState, useCallback, useRef } from 'react';
import { Message, ChatStatus } from '@/types';
import { streamClaudeResponse } from '@/services/claudeService';

export function useChat() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [status, setStatus] = useState<ChatStatus>('idle');
  const [error, setError] = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const sendMessage = useCallback(async (userInput: string) => {
    if (!userInput.trim() || status === 'loading' || status === 'streaming') return;

    const userMessage: Message = {
      id: crypto.randomUUID(),
      role: 'user',
      content: userInput.trim(),
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setStatus('loading');
    setError(null);

    const aiMessage: Message = {
      id: crypto.randomUUID(),
      role: 'assistant',
      content: '',
      timestamp: new Date(),
      isStreaming: true
    };

    setMessages(prev => [...prev, aiMessage]);

    abortRef.current = new AbortController();

    try {
      setStatus('streaming');
      for await (const token of streamClaudeResponse(
        [...messages, userMessage],
        abortRef.current.signal
      )) {
        setMessages(prev =>
          prev.map(m =>
            m.id === aiMessage.id
              ? { ...m, content: m.content + token }
              : m
          )
        );
      }
    } catch (e) {
      setError('AI 응답 중 오류가 발생했습니다. 다시 시도해 주세요.');
    } finally {
      setMessages(prev =>
        prev.map(m =>
          m.id === aiMessage.id ? { ...m, isStreaming: false } : m
        )
      );
      setStatus('idle');
    }
  }, [messages, status]);

  const stopStreaming = useCallback(() => {
    abortRef.current?.abort();
    setStatus('idle');
  }, []);

  return { messages, status, error, sendMessage, stopStreaming };
}
```

