```tsx
import { useState, useRef, KeyboardEvent } from 'react';
import { ChatStatus } from '@/types';
import styles from './ChatInput.module.css';

interface ChatInputProps {
  onSend: (message: string) => void;
  onStop: () => void;
  status: ChatStatus;
}

export function ChatInput({ onSend, onStop, status }: ChatInputProps) {
  const [input, setInput] = useState('');
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const isActive = status === 'loading' || status === 'streaming';

  const handleSend = () => {
    if (!input.trim() || isActive) return;
    onSend(input);
    setInput('');
    textareaRef.current?.focus();
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleInput = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInput(e.target.value);
    // auto-resize
    const ta = e.target;
    ta.style.height = 'auto';
    ta.style.height = Math.min(ta.scrollHeight, 120) + 'px';
  };

  return (
    <div className={styles.container} role="form" aria-label="메시지 입력">
      <div className={styles.inputWrapper}>
        <textarea
          ref={textareaRef}
          className={styles.textarea}
          value={input}
          onChange={handleInput}
          onKeyDown={handleKeyDown}
          placeholder="보험 관련 질문을 입력하세요... (Enter로 전송)"
          rows={1}
          maxLength={2000}
          disabled={isActive}
          aria-label="메시지 입력창"
          aria-describedby="input-hint"
        />
        <span id="input-hint" className={styles.srOnly}>
          Enter 키로 전송, Shift+Enter로 줄바꿈
        </span>
        {isActive ? (
          <button
            className={`${styles.btn} ${styles.stopBtn}`}
            onClick={onStop}
            aria-label="AI 응답 중지"
            type="button"
          >
            ■
          </button>
        ) : (
          <button
            className={`${styles.btn} ${styles.sendBtn}`}
            onClick={handleSend}
            disabled={!input.trim()}
            aria-label="메시지 전송"
            type="button"
          >
            ↑
          </button>
        )}
      </div>
      <p className={styles.hint}>{input.length}/2000</p>
    </div>
  );
}
