import { useState, useCallback } from 'react';
import { useChat } from '@/hooks/useChat';
import { InsuranceProduct } from '@/types';
import { MessageList } from '@/components/MessageList/MessageList';
import { ChatInput } from '@/components/ChatInput/ChatInput';
import { ProductCarousel } from '@/components/ProductCarousel/ProductCarousel';
import styles from './App.module.css';

export default function App() {
  const { messages, status, error, sendMessage, stopStreaming } = useChat();
  const [showProducts, setShowProducts] = useState(true);

  const handleProductSelect = useCallback((product: InsuranceProduct) => {
    sendMessage(`${product.name} (${product.company}) 상품에 대해 자세히 설명해주세요.`);
    setShowProducts(false);
  }, [sendMessage]);

  return (
    <div className={styles.app}>
      {/* 헤더 */}
      <header className={styles.header} role="banner">
        <div className={styles.headerContent}>
          <h1 className={styles.logo}>보험 AI 어시스턴트</h1>
          <button
            className={styles.toggleBtn}
            onClick={() => setShowProducts(p => !p)}
            aria-expanded={showProducts}
            aria-controls="product-section"
          >
            추천 상품 {showProducts ? '숨기기' : '보기'}
          </button>
        </div>
      </header>

      <main className={styles.main} role="main">
        {/* 상품 캐러셀 (접을 수 있음) */}
        {showProducts && (
          <div id="product-section">
            <ProductCarousel onProductSelect={handleProductSelect} />
          </div>
        )}

        {/* 에러 메시지 */}
        {error && (
          <div className={styles.error} role="alert" aria-live="assertive">
            {error}
          </div>
        )}

        {/* 메시지 영역 */}
        <div className={styles.chatArea}>
          {messages.length === 0 && (
            <div className={styles.emptyState} aria-label="채팅 시작 안내">
              <p>안녕하세요! 보험 상담 관련 질문을 입력해주세요.</p>
              <p className={styles.hint}>예: "실손보험 추천해주세요" / "종신보험과 정기보험 차이는?"</p>
            </div>
          )}
          <MessageList messages={messages} status={status} />
        </div>
      </main>

      {/* 입력 영역 - 항상 하단 고정 */}
      <footer className={styles.footer} role="contentinfo">
        <ChatInput onSend={sendMessage} onStop={stopStreaming} status={status} />
      </footer>
    </div>
  );
}
```

